import React, { Component } from 'react';
import { Elevation } from '@rmwc/elevation';
import { Radio } from '@rmwc/radio';

class Question extends Component {
  render() {
      console.log(this.props.questionObject);
      let questionObject=this.props.questionObject;
      

      return (

        <section className="question">
            <Elevation z={12}>
                <div className="current-progress">{this.props.current}/{this.props.total}</div>
                <h3>{questionObject.question}</h3>
                <div className="options">
                    {
                        questionObject.options.map((option,index)=>{
                            let clickFunc=()=>this.props.sendAnswer(option);
                            if(this.props.isLastQuestion)
                            {
                            clickFunc=()=>this.props.nextPhase(option);
                            }
                            return (
                                <Radio
                                name="optionGroup"
                                key={index}
                                onClick={clickFunc}
                                checked={false}
                                readOnly
                                >
                            {option.Text}
                            </Radio>);
                        })
                    }
                </div>
            </Elevation>
        </section>
      );
  }
}

export default Question;
