import React, { Component } from 'react';
import questions from '../data/questions.js';
import p2questions from '../data/p2questions.js';
import p3questions from '../data/p3questions.js';

import Button from '@material-ui/core/Button';
import { LinearProgress } from '@rmwc/linear-progress';
import { Elevation } from '@rmwc/elevation';

import Question from './Question';
import P2Question from './P2Question';
import Result from './Result';

class Test extends Component {

  constructor(props)
  {
      super(props);
      this.state={
        questions:questions,
        currentQuestion:0,
        phase:-1
      };
      this.startTest=this.startTest.bind(this);
      this.nextQuestion=this.nextQuestion.bind(this);
      this.sendAnswer=this.sendAnswer.bind(this);
      this.nextPhase=this.nextPhase.bind(this);
  }

  startTest()
  {
    this.setState({phase:this.state.phase+1});
  }

  nextQuestion()
  {
    this.setState({currentQuestion:this.state.currentQuestion+1});
  }

  nextPhase(option)
  {
      //optionu kaydet
    let phase=this.state.phase+1;
    let questions=this.state.questions;
    console.log(phase)
    if(phase===1)
    {
      questions=p2questions;
    }
    if(phase===2)
    {
      questions=p3questions;
      console.log(questions)
    }
    this.setState({phase:phase,currentQuestion:0,questions:questions});
  }

  sendAnswer(option)
  {
    //optionu kaydet
    this.nextQuestion();
  }

  renderStartScreen()
  {
    return(
        <section className="welcome">
          <Elevation z={12}>
            <div className="content">
                <h1>Kişilik testi</h1>
                <p>
                Lorem ipsum dolor sit amet, consectetur adipiscing elit.
                </p>
                <Button variant="contained" color="primary" onClick={this.startTest}>Başla</Button>
            </div>
            </Elevation>
        </section>
    );
  }

  render() {
      //start phase
      let isLast=this.state.currentQuestion+1>=this.state.questions.length;
      if(this.state.phase===-1)
      {
          return this.renderStartScreen();
      }
      //phase1
      if(this.state.phase===0)
      {
        return (
          <div>
          <LinearProgress progress={this.state.currentQuestion/this.state.questions.length} />
            <Question 
              isLastQuestion={isLast}
              questionObject={this.state.questions[this.state.currentQuestion]}
              sendAnswer={this.sendAnswer}
              nextPhase={this.nextPhase}
              current={this.state.currentQuestion}
              total={this.state.questions.length}
            >
            </Question>
          </div>
        );
      }
      //phase 2
      else if(this.state.phase===1){
        return (            
            <P2Question 
                isLastQuestion={isLast}
                questionObject={this.state.questions[this.state.currentQuestion]}
                sendAnswer={this.sendAnswer}
                nextPhase={this.nextPhase}
            />)
      }
      else if(this.state.phase===2)
      {
        return (            
            <P2Question 
                isLastQuestion={isLast}
                questionObject={this.state.questions[this.state.currentQuestion]}
                sendAnswer={this.sendAnswer}
                nextPhase={this.nextPhase}
            />)
      }
      else{
          return <Result/>
      }

  }
}

export default Test;
